  console.error(err);                        // log server-side
  res.status(500).json({ error: 'Internal error' }); // no stack to client
});
```

#### 6. No graceful shutdown (Informational)

Not strictly security, but `SIGTERM` handling avoids dropped in-flight connections:

```js
const server = app.listen(port, host, () => { /* ... */ });
process.on('SIGTERM', () => server.close(() => process.exit(0)));
```

